// __fixtures__/users.ts
import { User } from '../types';

export function createUser(overrides: Partial<User> = {}): User {
  return {
    id: `user-${Date.now()}`,
    email: `user-${Date.now()}@example.com`,
    name: 'Test User',
    role: 'user',
    createdAt: new Date('2024-01-01'),  // Fixed date for snapshots
    ...overrides,
  };
}

// Named constants only for stable reference values
export const adminUser = createUser({ id: 'user-admin', role: 'admin' });

// Usage
const user = createUser({ role: 'admin', name: 'Alice' });

import { Factory } from 'fishery';
import { User } from '../types';

export const userFactory = Factory.define<User>(({ sequence }) => ({
  id: `user-${sequence}`,
  email: `user${sequence}@example.com`,  // Deterministic, not random
  name: 'Test User',
  role: 'user',
  createdAt: new Date('2024-01-01'),
}));

// Traits
export const adminUserFactory = userFactory.params({ role: 'admin' });

// Usage
const user = userFactory.build({ name: 'Alice' });
const admin = adminUserFactory.build();
const [u1, u2] = userFactory.buildList(2);
